solution: ```class Solution {
public:
    int binaryGap(int n) {
        int last = -1, maxGap = 0, pos = 0;
        while (n) {
            if (n & 1) {
                if (last != -1) maxGap = max(maxGap, pos - last);
                last = pos;
            }
            ++pos;
            n >>= 1;
        }
        return maxGap;
    }
};
